<template><ModulePageShell title="质控总览" description="完整病例范围、26项指标和缺陷闭环的真实入口"><template #toolbar><a-button :loading="loading" @click="reload">刷新</a-button></template><template #stats><MetricCard label="纳入病例" :value="caseTotal" icon="IconFile"/><MetricCard label="质控指标" :value="indicators.length" icon="IconBarChart"/><MetricCard label="异常指标" :value="abnormal" icon="IconExclamationCircle" variant="danger"/><MetricCard label="未关闭缺陷" :value="openDefects" icon="IconClockCircle" variant="warn"/></template><a-alert v-if="error" type="error" show-icon>{{error}}</a-alert><a-empty v-else-if="!loading&&!caseTotal" description="服务端当前没有可纳入质控的OperationCase"/><div v-else class="entry-grid"><a-card class="section-card" title="专业指标" :bordered="false"><p>显示分母、分子、排除条件、证据字段和病例穿透。</p><a-button type="primary" @click="router.push('/quality/dashboard')">进入26项指标</a-button></a-card><a-card class="section-card" title="缺陷闭环" :bordered="false"><p>按版本执行整改、复核和关闭，不修改临床源记录。</p><a-button @click="router.push('/quality/defects')">进入缺陷管理</a-button></a-card><a-card class="section-card" title="专项与报表" :bordered="false"><a-space wrap><a-link @click="router.push('/quality/hypothermia')">低体温</a-link><a-link @click="router.push('/quality/pacu')">PACU</a-link><a-link @click="router.push('/quality/adverse-events')">不良事件</a-link><a-link @click="router.push('/quality/reports')">月度报表</a-link></a-space></a-card></div></ModulePageShell></template>
<script setup lang="ts">import{computed,onMounted,ref}from'vue';import{useRouter}from'vue-router';import MetricCard from'@/components/MetricCard.vue';import ModulePageShell from'@/components/shared/ModulePageShell.vue';import{qualityApi,type QualityIndicatorApi}from'@/api/quality';const router=useRouter(),loading=ref(false),error=ref(''),caseTotal=ref(0),indicators=ref<QualityIndicatorApi[]>([]),defects=ref<{status:string}[]>([]);const abnormal=computed(()=>indicators.value.filter(x=>x.status==='abnormal'||x.status==='warning').length),openDefects=computed(()=>defects.value.filter(x=>x.status!=='closed').length);async function reload(){loading.value=true;error.value='';try{const[c,i,d]=await Promise.all([qualityApi.caseList({page:1,pageSize:1}),qualityApi.getIndicators(),qualityApi.defectList({page:1,pageSize:100})]);caseTotal.value=c.total;indicators.value=i;defects.value=d.list;}catch(e){caseTotal.value=0;indicators.value=[];defects.value=[];error.value=`加载失败：${(e as Error).message}`;}finally{loading.value=false;}}onMounted(reload);</script>
<style scoped>.entry-grid{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:12px}.entry-grid p{color:var(--text-secondary)}@media(max-width:960px){.entry-grid{grid-template-columns:1fr}}</style>
